[
  {
    "text": "Define 'composite nature' of quantum solitons as their underlying multi-photon bound-state structure, where the interference arises from relative phases of constituent Fock-state components.",
    "topic": "definition of composite nature"
  },
  {
    "text": "The quantum walk pattern in the soliton's spatial probability distribution is a direct consequence of the entangled evolution of its constituent photons, thereby revealing the composite nature.",
    "topic": "mechanism of quantum walk"
  },
  {
    "text": "The solitonic character is reflected in the persistence of the quantum walk envelope without dispersion, which would not occur for a product state of independent photons.",
    "topic": "signature of solitonic character"
  },
  {
    "text": "Propose a time-resolved measurement of two-photon correlations in a transmon array to separately extract the single-particle and bound-state contributions to the interference pattern.",
    "topic": "experimental discrimination"
  }
]
